// Loan Eligibility Checker

const age              = 30;
const monthlyIncome    = 35000;
const hasExistingLoan  = false;

// Check all three criteria with &&
if (age >= 21 && age <= 60 && monthlyIncome >= 25000 && !hasExistingLoan) {
    console.log("Eligible");
} else {
    console.log("Not eligible");
}

